def verify(output: str):
    # Input validation: check length
    if len(output) != 700:
        return (False, 0.0, f"String length is {len(output)}, expected 700.")

    # Convert to string of digits (already string, but ensure all chars are digits)
    if not output.isdigit():
        return (False, 0.0, "String contains non-digit characters.")

    # Count digit frequencies
    digit_counts = {str(d): output.count(str(d)) for d in range(10)}

    # Constraint 1: The number of digit 8 is prime.
    count_8 = digit_counts['8']
    def is_prime(n):
        if n < 2:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False
        for i in range(3, int(n**0.5) + 1, 2):
            if n % i == 0:
                return False
        return True

    constraint1 = is_prime(count_8)

    # Constraint 2: The number of digit 3 is exactly 3× the number of digit 6.
    count_3 = digit_counts['3']
    count_6 = digit_counts['6']
    constraint2 = (count_3 == 3 * count_6)

    # Constraint 3: The number of digit 4 is a multiple of 8.
    count_4 = digit_counts['4']
    constraint3 = (count_4 % 8 == 0)

    # Constraint 4: The total number of even digits (0,2,4,6,8) is exactly 400.
    even_digits = ['0', '2', '4', '6', '8']
    total_even = sum(digit_counts[d] for d in even_digits)
    constraint4 = (total_even == 400)

    # Constraint 5: Exactly 12 occurrences of substring "2026", non-overlapping, no others.
    pattern = "2026"
    count_2026 = 0
    i = 0
    while i <= len(output) - len(pattern):
        if output[i:i+len(pattern)] == pattern:
            count_2026 += 1
            i += len(pattern)  # skip to avoid overlapping matches
        else:
            i += 1
    constraint5 = (count_2026 == 12)

    # Constraint 6: No occurrence of "000"
    constraint6 = ("000" not in output)

    # Constraint 7: Must not start with '0' and must end with an odd digit.
    constraint7 = (output[0] != '0' and output[-1] in '13579')

    # Constraint 8: Every digit has to appear at least 7 times.
    constraint8 = all(count >= 7 for count in digit_counts.values())

    # Collect all constraints
    constraints = [
        constraint1, constraint2, constraint3, constraint4,
        constraint5, constraint6, constraint7, constraint8
    ]
    total_constraints = len(constraints)
    satisfied_count = sum(constraints)
    score = satisfied_count / total_constraints

    # Build message
    failed_constraints = []
    if not constraint1:
        failed_constraints.append("digit 8 count is not prime")
    if not constraint2:
        failed_constraints.append(f"digit 3 count ({count_3}) != 3 * digit 6 count ({count_6})")
    if not constraint3:
        failed_constraints.append(f"digit 4 count ({count_4}) is not multiple of 8")
    if not constraint4:
        failed_constraints.append(f"even digit count ({total_even}) != 400")
    if not constraint5:
        failed_constraints.append(f"substring '2026' count ({count_2026}) != 12")
    if not constraint6:
        failed_constraints.append("contains '000'")
    if not constraint7:
        failed_constraints.append("starts with '0' or ends with even digit")
    if not constraint8:
        digits_under_7 = [d for d, cnt in digit_counts.items() if cnt < 7]
        failed_constraints.append(f"some digit(s) appear <7 times: {', '.join(digits_under_7)}")

    if not any(constraints):
        message = "; ".join(failed_constraints)
    elif satisfied_count == total_constraints:
        message = "All constraints satisfied."
    else:
        message = "; ".join(failed_constraints)

    return (satisfied_count == total_constraints, score, message)
